create table dirkspzm32.isi_res_prod_platz (
    sid               varchar2(2 char) not null enable,
    firma_nr          number(6, 0) not null enable,
    res_id            number(*, 0) not null enable,
    prod_platz_res_id number(*, 0) not null enable
);

alter table dirkspzm32.isi_res_prod_platz
